using System.Text.RegularExpressions;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ──────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_FormatsCorrectly()
    {
        var result = _formatter.FormatPhoneNumber("1234567890");

        Assert.AreEqual("(123) 456-7890", result);
        StringAssert.StartsWith(result, "(123)");
        StringAssert.EndsWith(result, "7890");
        StringAssert.Contains(result, "456");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.StartsWith(result, "(800)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFour()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_MatchesPattern()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.Matches(result, new Regex(@"^\(\d{3}\) \d{3}-\d{4}$"));
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    [DataRow("123")]
    [DataRow("12345678901")]
    [DataRow("")]
    public void FormatPhoneNumber_WrongLength_ThrowsArgumentException(string digits)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.FormatPhoneNumber(digits));
    }

    // ── BuildGreeting ──────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_FormatsCorrectly()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
        StringAssert.StartsWith(result, "Dear ");
        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_WithCustomTitle_UsesTitle()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        StringAssert.StartsWith(result, "Dear Dr.");
        StringAssert.EndsWith(result, "Johnson,");
        StringAssert.Contains(result, "Dr. Johnson");
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_InvalidName_Throws(string? name)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.BuildGreeting(name!));
    }

    // ── GenerateSlug ───────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseHyphenated()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_StripsNonAlphanumeric()
    {
        var result = _formatter.GenerateSlug("C# is Great!!!");

        Assert.AreEqual("c-is-great", result);
        StringAssert.DoesNotMatch(result, new Regex(@"[^a-z0-9\-]"));
    }

    [TestMethod]
    public void GenerateSlug_TitleWithLeadingTrailingSpaces_Trims()
    {
        var result = _formatter.GenerateSlug("  Padded Title  ");

        Assert.AreEqual("padded-title", result);
        StringAssert.Matches(result, new Regex(@"^[a-z]"));
        StringAssert.Matches(result, new Regex(@"[a-z]$"));
    }

    [TestMethod]
    public void GenerateSlug_MixedCase_ReturnsAllLowercase()
    {
        var result = _formatter.GenerateSlug("The Quick Brown FOX");

        StringAssert.DoesNotMatch(result, new Regex(@"[A-Z]"));
        StringAssert.StartsWith(result, "the");
        StringAssert.EndsWith(result, "fox");
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_InvalidTitle_Throws(string? title)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.GenerateSlug(title!));
    }

    // ── FormatCurrency ─────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_PrependsDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        Assert.AreEqual("$9.99", result);
        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_PrependsSymbol()
    {
        var result = _formatter.FormatCurrency(49.90m, "€");

        StringAssert.StartsWith(result, "€");
        StringAssert.EndsWith(result, "49.90");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_ShowsTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(100m);

        StringAssert.EndsWith(result, ".00");
        StringAssert.Matches(result, new Regex(@"\.\d{2}$"));
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_FormatsCorrectly()
    {
        var result = _formatter.FormatCurrency(-5.50m);

        StringAssert.StartsWith(result, "$-");
        StringAssert.Contains(result, "5.50");
    }

    [TestMethod]
    public void FormatCurrency_Zero_ReturnsZeroFormatted()
    {
        var result = _formatter.FormatCurrency(0m);

        Assert.AreEqual("$0.00", result);
    }
}

